export type DataLine = {
  value: number;
  label?: number | string | null;
};

export type HistogramColorStops = HistogramClassedColorStop[] | HistogramContinuousColorStop[];

export type HistogramLayout = "horizontal" | "vertical";

export type HistogramContinuousColorStop = {
  color: HistogramColor;
  value: number;
};

export type HistogramClassedColorStop = {
  color?: HistogramColor;
  minValue: number;
  maxValue: number;
};

export type HistogramColor = number[] | string | {
    r?: number;
    g?: number;
    b?: number;
    a?: number;
};